export function IndiaZoomMap({ selectedState, className = "", pinColor = "white" }: IndiaZoomMapProps) {
  const selectedShape = STATE_SHAPES.find((shape) => shape.name === selectedState);
  const transform = useMemo(() => {
    if (!selectedShape) return "translate(0 0) scale(1)";
    const [cx, cy] = selectedShape.center;
    const scale = selectedShape.zoom;
    return `translate(180 208) scale(${scale}) translate(${-cx} ${-cy})`;
  }, [selectedShape]);

  return (
    <div className={`relative mx-auto aspect-[360/430] w-full max-w-[360px] ${className}`}>
      <svg viewBox="0 0 360 430" role="img" aria-label="Map of India" className="h-full w-full overflow-visible">
        <g className="transition-transform duration-1000 ease-[cubic-bezier(.2,.85,.2,1)]" transform={transform}>
          {STATE_SHAPES.map((shape) => {
            const active = shape.name === selectedState;
            return (
              <path
                key={shape.name}
                d={shape.path}
                className={active ? "india-state india-state-active" : "india-state"}
                vectorEffect="non-scaling-stroke"
              />
            );
          })}
        </g>
      </svg>

      <div
        className={`pointer-events-none absolute left-1/2 top-[48%] -translate-x-1/2 -translate-y-full transition-all duration-700 ease-out ${selectedShape ? "scale-100 opacity-100" : "scale-75 opacity-0"}`}
        aria-hidden
      >
        <svg width="25" height="31" viewBox="0 0 24 30" fill="none" className="drop-shadow-[0_0_12px_rgba(255,255,255,.65)]">
          <path d="M12 0C5.4 0 0 5.4 0 12c0 9 12 18 12 18s12-9 12-18C24 5.4 18.6 0 12 0zm0 16a4 4 0 110-8 4 4 0 010 8z" fill={pinColor} />
        </svg>
      </div>
    </div>
  );
}
